refsection.programlisting:
slice = imresize(rgb2gray(imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"))), [16 24]);
volume = cat(3, slice, slice, slice);
volume(8, 12, 2) = 255;
out = immedian3(volume, [3 3 3]);
subplot(1, 2, 1);
imshow(volume(:, :, 2));
subplot(1, 2, 2);
imshow(out(:, :, 2));
